1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / trivial cases ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums for main items (single item, no modifiers, 1st-time customer with no prior contract) ---
15	  // For these isolated base-premium tests we expect: base + 10% first insurance + 5 fee, rounded up in MHPCO's favor.
16	  it("quote for a single plain sword (steel, enchantment 3) → 100 base + 10 first-insurance + 5 fee = 115 G", () => {
17	    const result = processScenario({
18	      customer: { yearsWithMHPCO: 0 },
19	      steps: [
20	        {
21	          op: "quote",
22	          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
23	        },
24	      ],
25	    });
26	    expect(result).toEqual({ results: [{ premium: 115 }] });
27	  });
28	  it("quote for a single plain amulet → 60 base + 6 first-insurance + 5 fee = 71 G", () => {
29	    const result = processScenario({
30	      customer: { yearsWithMHPCO: 0 },
31	      steps: [
32	        {
33	          op: "quote",
34	          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
35	        },
36	      ],
37	    });
38	    expect(result).toEqual({ results: [{ premium: 71 }] });
39	  });
40	  it("quote for a single plain staff → 80 base + 8 first-insurance + 5 fee = 93 G", () => {
41	    const result = processScenario({
42	      customer: { yearsWithMHPCO: 0 },
43	      steps: [
44	        {
45	          op: "quote",
46	          items: [{ type: "staff", material: "oak", enchantment: 1, cursed: false }],
47	        },
48	      ],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 93 }] });
51	  });
52	  it("quote for a single plain potion → 40 base + 4 first-insurance + 5 fee = 49 G", () => {
53	    const result = processScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [
56	        {
57	          op: "quote",
58	          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
59	        },
60	      ],
61	    });
62	    expect(result).toEqual({ results: [{ premium: 49 }] });
63	  });
64	
65	  // --- Component base premiums and blocks of 3 alike ---
66	  it("2 runes → 50 base + 5 first-insurance + 5 fee = 60 G", () => {
67	    const result = processScenario({
68	      customer: { yearsWithMHPCO: 0 },
69	      steps: [
70	        {
71	          op: "quote",
72	          items: [{ type: "rune" }, { type: "rune" }],
73	        },
74	      ],
75	    });
76	    expect(result).toEqual({ results: [{ premium: 60 }] });
77	  });
78	  it("3 runes → 60 base (block) + 6 first-insurance + 5 fee = 71 G", () => {
79	    const result = processScenario({
80	      customer: { yearsWithMHPCO: 0 },
81	      steps: [
82	        {
83	          op: "quote",
84	          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
85	        },
86	      ],
87	    });
88	    expect(result).toEqual({ results: [{ premium: 71 }] });
89	  });
90	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
91	  it.todo("7 runes → 175 G base premium (no blocks formed; spec example)");
92	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
93	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
94	
95	  // --- Premium modifiers in isolation (newcomer scenarios anchor expected totals) ---
96	  it.todo("newcomer with a cursed sword (steel, enchantment 3) → premium 165 G (integration example)");
97	  it.todo("sword with enchantment 4 (not cursed) → no high-enchantment surcharge");
98	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
99	  it.todo("cursed sword with exactly enchantment 5 → both surcharges apply");
100	
101	  // --- Modifier scope on multi-item policies ---
102	  it.todo("cursed sword + plain amulet → base 160 G, +50 G curse surcharge on the sword only → 210 G before policy modifiers and fee");
103	
104	  // --- Loyalty / first insurance / follow-up modifiers ---
105	  it.todo("customer with exactly 2 years → loyalty discount applies");
106	  it.todo("long-standing customer's second contract: cursed sword enchantment 7 → premium 160 G (integration example; first insurance surcharge still applies per item)");
107	
108	  // --- Rounding in MHPCO's favor ---
109	  it.todo("a premium calculation that yields 197.5 G → final premium 198 G (rounded up)");
110	  it.todo("a payout calculation that yields 350.5 G → final payout 350 G (rounded down)");
111	
112	  // --- Claim processing: deductibles and standard reimbursement ---
113	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full reimbursement minus 100 G deductible)");
114	  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (full reimbursement minus 100 G deductible)");
115	  it.todo("dragon attack damages an insured sword (500 G) and amulet (300 G) → payout 600 G (100 G deductible per damaged item)");
116	
117	  // --- Claim processing: special clauses ---
118	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50 % rule wins, then deductible)");
119	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (only dragon-material clause applies)");
120	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (only high-enchantment clause applies)");
121	  it.todo("dragon-material sword with exactly enchantment 8, damage 1000 G → payout 400 G (high-enchantment clause applies first, then deductible)");
122	
123	  // --- Multiple items of same type and cap exhaustion ---
124	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G; dragon attack damages both → each entry treated as separate damage with its own deductible");
125	  it.todo("policy covers a sword and an amulet → insurance sum 1600 G, cap 3200 G");
126	  it.todo("cursed sword (insurance value 1000 G) → cap 2000 G (based on unmodified insurance value)");
127	  it.todo("policy covers a sword and 3 runes (block) → insurance sum 1750 G (block discount affects premium only, not insurance sum)");
128	  it.todo("sword insured (cap 2000 G); first claim 1500 G → payout 1400 G, remainingCap 600 G");
129	  it.todo("sword insured (cap 2000 G); after first 1500 G claim, second claim 1500 G → payout 600 G, remainingCap 0 G");
130	
131	  // --- Error/edge cases ---
132	  it.todo("quote includes an item with an unknown type → throws an error (CLI exits non-zero)");
133	  it.todo("claim references a damage entry whose item is not part of the policy → throws an error");
134	  it.todo("claim has more damage entries of a given type than the policy covers → throws an error");
135	  it.todo("claim contains a damage entry with amount: -200 → throws an error");
136	});
