1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const FLOAT_ROUNDING_TOLERANCE = 1e-9;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	};
12	
13	type Item = { type: string };
14	type QuoteStep = { op: "quote"; items: Array<Item> };
15	type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Array<QuoteStep>;
18	};
19	
20	const roundUpInMHPCOFavor = (amount: number): number =>
21	  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);
22	
23	const basePremiumFor = (items: Array<Item>): number => {
24	  const runes = items.filter((item) => item.type === "rune").length;
25	  if (runes === 3) return 60;
26	  return items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
27	};
28	
29	const withFirstInsuranceSurcharge = (amount: number): number =>
30	  amount * (1 + FIRST_INSURANCE_SURCHARGE);
31	
32	const withProcessingFee = (amount: number): number => amount + PROCESSING_FEE;
33	
34	const quoteStep = (step: QuoteStep): { premium: number } => {
35	  const basePremium = basePremiumFor(step.items);
36	  const premiumBeforeRounding = withProcessingFee(
37	    withFirstInsuranceSurcharge(basePremium),
38	  );
39	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
40	};
41	
42	export const processScenario = (scenario: unknown): unknown => {
43	  const { steps } = scenario as Scenario;
44	  return { results: steps.map(quoteStep) };
45	};
